// Import Component
import { useEffect } from "react";
import useTitle from "../../hooks/useTitle";

import Hero from "~/pages/HomePage/Hero";
import CategoryHighlights from "~/pages/HomePage/CategoryHighlights";
import FeaturedProducts from "~/pages/HomePage/FeaturedProducts";
import Marquee from "~/pages/HomePage/Marquee";
import BestSales from "~/pages/HomePage/BestSales";
import BrandLogos from "~/pages/HomePage/BrandLogos";
import VideoPromo from "~/pages/HomePage/VideoPromo";
import Testimonial from "~/pages/HomePage/Testimonial";
import BlogPosts from "~/pages/HomePage/BlogPosts";


// Library
// AOS
import AOS from "aos";
import "aos/dist/aos.css"; // Import file CSS của AOS

const App = () => {
    useTitle("Home");
    useEffect(() => {
        AOS.init({
            duration: 2500,
            anchorPlacement: "top-bottom",
            once: true,
        });
    }, []);
    return (
        <>
            {/* Main Content */}
            <main className="main">
                <Hero />
                <CategoryHighlights />
                <FeaturedProducts />
                <Marquee />
                <BestSales />
                <BrandLogos />
                <VideoPromo />
                <Testimonial />
                <BlogPosts />
            </main>
        </>
    );
};

export default App;
